import os
from google.cloud import storage

def process_image(event, context):
    # Get filename and bucket name from event metadata
    filename = event['name']
    bucket_name = event['bucket']

    # Define conversion options (e.g., resize, format)
    convert_options = {
        'resize': '600',
        'format': 'jpg'
    }

    # Extract conversion options from event metadata
    for key in convert_options:
        if key in event['metadata']:
            value = event['metadata'][key]
            convert_options[key] = value

    # Construct ImageMagick convert command using subprocess.call()
    cmd = f"convert -resize {convert_options.get('resize', 'default')} -format {convert_options.get('format', 'jpg')} gs://{bucket_name}/{filename} gs://{bucket_name}/converted_{filename}"

    try:
        # Run the ImageMagick convert command
        process = subprocess.Popen(cmd, shell=True)
        process.wait()
    except Exception as e:
        print(f"Error processing image: {str(e)}")

